var numWaterBottles = function(numBottles, numExchange) {
    let total = numBottles;
    let empty = numBottles;
    while (empty >= numExchange) {
        const newBottles = Math.floor(empty / numExchange);
        total += newBottles;
        empty = (empty % numExchange) + newBottles;
    }
    return total;
};
